{
  "mode": "method",
  "tests": [
    {
      "name": "winners_not_displayed",
      "input": {"submissions": [{"id": 1, "status": "winner"}, {"id": 2, "status": "winner"}, {"id": 3, "status": "winner"}, {"id": 4, "status": "placement"}, {"id": 5, "status": "placement"}]},
      "output": [],
      "notes": "Ensures that winners and placements are not displayed in the SUBMISSION/SCREENING tab."
    },
    {
      "name": "only_non_winners_displayed",
      "input": {"submissions": [{"id": 1, "status": "placement"}, {"id": 2, "status": "placement"}, {"id": 3, "status": "placement"}]},
      "output": [{"id": 1, "status": "placement"}, {"id": 2, "status": "placement"}, {"id": 3, "status": "placement"}],
      "notes": "Validates that only non-winners are displayed when there are no winners."
    },
    {
      "name": "no_submissions",
      "input": {"submissions": []},
      "output": [],
      "notes": "Tests the edge case where there are no submissions at all."
    },
    {
      "name": "mixed_status_submissions",
      "input": {"submissions": [{"id": 1, "status": "winner"}, {"id": 2, "status": "placement"}, {"id": 3, "status": "loser"}]},
      "output": [{"id": 2, "status": "placement"}, {"id": 3, "status": "loser"}],
      "notes": "Checks that only non-winners are displayed when mixed statuses are present."
    },
    {
      "name": "all_winners",
      "input": {"submissions": [{"id": 1, "status": "winner"}, {"id": 2, "status": "winner"}, {"id": 3, "status": "winner"}]},
      "output": [],
      "notes": "Validates that no submissions are displayed when all are winners."
    },
    {
      "name": "single_submission_winner",
      "input": {"submissions": [{"id": 1, "status": "winner"}]},
      "output": [],
      "notes": "Tests the case with a single submission that is a winner."
    },
    {
      "name": "single_submission_non_winner",
      "input": {"submissions": [{"id": 1, "status": "placement"}]},
      "output": [{"id": 1, "status": "placement"}],
      "notes": "Tests the case with a single submission that is a non-winner."
    },
    {
      "name": "multiple_placements",
      "input": {"submissions": [{"id": 1, "status": "placement"}, {"id": 2, "status": "placement"}, {"id": 3, "status": "placement"}, {"id": 4, "status": "winner"}]},
      "output": [{"id": 1, "status": "placement"}, {"id": 2, "status": "placement"}, {"id": 3, "status": "placement"}],
      "notes": "Ensures that multiple placements are displayed correctly when a winner is present."
    }
  ],
  "assumptions": "Winners should not be displayed in the SUBMISSION/SCREENING tab under any circumstances.",
  "notes": "Focus on ensuring that the filtering logic for winners is correctly implemented."
}
